import { toItems } from '../../items/item.js';
import { toServerForms } from '../../server/forms/form.js';
import { serializeRawServerFormsValue } from '../forms/value.js';
export const toServerItemList = (sonolus, localize, toItem, list, searches) => ({
    title: list.title && localize(list.title),
    pageCount: list.pageCount,
    cursor: list.cursor,
    items: toItems(sonolus, localize, toItem, list.items),
    searches: list.searches && toServerForms(localize, list.searches, searches),
    quickSearchValues: list.quickSearchValue && serializeRawServerFormsValue(list.quickSearchValue, searches),
});
